/**
 * Self-contained formalization reducer test.
 *
 * Run:
 *   pnpm run gnode -- run open-source/gnosis/src/__tests__/transformation-family-formalization.test.ts
 */

import assert from 'node:assert';
import {
  TRANSFORMATION_FAMILY_THEOREM_IDS,
  buildTransformationFamilySignalFromDecompositionAttempt,
  buildTransformationFamilySignalFromReinforcementAttempt,
  deriveTransformationFamilyFromDecompositionAttempts,
  deriveTransformationFamilyFormalization,
  deriveTransformationFamilyFromReinforcementAttempts,
} from '../transformation-family-formalization';

const BASE_SIGNALS = [
  {
    id: 'reinforce-blade',
    beforeCrossings: 5,
    afterCrossings: 5,
    beforeWeight: 4,
    afterWeight: 11,
  },
  {
    id: 'featureless-push',
    beforeCrossings: 0,
    afterCrossings: 0,
    beforeWeight: 2,
    afterWeight: 9,
  },
  {
    id: 'project-from-void',
    beforeCrossings: 0,
    afterCrossings: 3,
    beforeWeight: 0,
    afterWeight: 2,
  },
  {
    id: 'decompose-barrier',
    beforeCrossings: 7,
    afterCrossings: 2,
    beforeWeight: 10,
    afterWeight: 3,
  },
];

const deterministicA = deriveTransformationFamilyFormalization({
  generatedAt: '2026-04-10T01:00:00.000Z',
  source: 'test-suite',
  signals: BASE_SIGNALS,
});

const deterministicB = deriveTransformationFamilyFormalization({
  generatedAt: '2026-04-10T01:00:00.000Z',
  source: 'test-suite',
  signals: [...BASE_SIGNALS].reverse(),
});

assert.deepStrictEqual(deterministicA, deterministicB);
assert.strictEqual(deterministicA.generatedAt, '2026-04-10T01:00:00.000Z');
assert.strictEqual(deterministicA.source, 'test-suite');
assert.strictEqual(deterministicA.entries.length, 4);
assert.strictEqual(deterministicA.aggregate.total, 4);
assert.strictEqual(deterministicA.aggregate.projectionCount, 1);
assert.strictEqual(deterministicA.aggregate.reinforcementCount, 1);
assert.strictEqual(deterministicA.aggregate.decompositionCount, 1);
assert.strictEqual(deterministicA.aggregate.unclassifiedCount, 1);
assert.strictEqual(deterministicA.aggregate.featurelessBeforeCount, 2);
assert.strictEqual(deterministicA.aggregate.featurelessAfterCount, 1);
assert.strictEqual(deterministicA.aggregate.restorationRequiredCount, 1);

const projection = deterministicA.entries.find(
  (entry) => entry.id === 'project-from-void'
);
assert.ok(projection);
assert.strictEqual(projection!.family, 'projection');
assert.strictEqual(projection!.validProjection, true);
assert.strictEqual(projection!.crossingsDelta, 3);

const reinforcement = deterministicA.entries.find(
  (entry) => entry.id === 'reinforce-blade'
);
assert.ok(reinforcement);
assert.strictEqual(reinforcement!.family, 'reinforcement');
assert.strictEqual(reinforcement!.validReinforcement, true);
assert.strictEqual(reinforcement!.weightDelta, 7);

const decomposition = deterministicA.entries.find(
  (entry) => entry.id === 'decompose-barrier'
);
assert.ok(decomposition);
assert.strictEqual(decomposition!.family, 'decomposition');
assert.strictEqual(decomposition!.validDecomposition, true);
assert.strictEqual(decomposition!.crossingsDelta, -5);

const unclassified = deterministicA.entries.find(
  (entry) => entry.id === 'featureless-push'
);
assert.ok(unclassified);
assert.strictEqual(unclassified!.family, 'unclassified');
assert.strictEqual(unclassified!.restorationRequired, true);
assert.strictEqual(unclassified!.featurelessBefore, true);

for (const theoremId of TRANSFORMATION_FAMILY_THEOREM_IDS) {
  assert.ok(deterministicA.theoremIds.includes(theoremId));
}

const reinforcementBridge = deriveTransformationFamilyFromReinforcementAttempts(
  {
    generatedAt: '2026-04-10T02:00:00.000Z',
    source: 'reinforcement-bridge-suite',
    attempts: [
      {
        id: 'wooden-sword',
        attempt: {
          target: {
            crossings: 12,
            weight: 3,
            capacity: 20,
            invariant: 42,
          },
          analysis: {
            mappedCrossings: 12,
            totalCrossings: 12,
            accuracy: 100,
          },
          energy: 15,
        },
      },
      {
        id: 'featureless-diamond',
        attempt: {
          target: {
            crossings: 0,
            weight: 100,
            capacity: 50,
            invariant: 99,
          },
          analysis: {
            mappedCrossings: 0,
            totalCrossings: 0,
            accuracy: 100,
          },
          energy: 30,
        },
      },
      {
        id: 'fragile-lightbulb',
        attempt: {
          target: {
            crossings: 4,
            weight: 5,
            capacity: 6,
            invariant: 77,
          },
          analysis: {
            mappedCrossings: 4,
            totalCrossings: 4,
            accuracy: 100,
          },
          energy: 10,
        },
      },
    ],
  }
);

assert.strictEqual(reinforcementBridge.generatedAt, '2026-04-10T02:00:00.000Z');
assert.strictEqual(reinforcementBridge.source, 'reinforcement-bridge-suite');
assert.strictEqual(reinforcementBridge.aggregate.totalAttempts, 3);
assert.strictEqual(reinforcementBridge.aggregate.successCount, 1);
assert.strictEqual(reinforcementBridge.aggregate.fizzleCount, 1);
assert.strictEqual(reinforcementBridge.aggregate.shatterCount, 1);
assert.strictEqual(reinforcementBridge.aggregate.emittedSignalCount, 1);
assert.strictEqual(reinforcementBridge.aggregate.restorationRequiredCount, 1);
assert.strictEqual(reinforcementBridge.formalization.aggregate.total, 1);
assert.strictEqual(
  reinforcementBridge.formalization.aggregate.reinforcementCount,
  1
);

const woodenSword = reinforcementBridge.attempts.find(
  (entry) => entry.id === 'wooden-sword'
);
assert.ok(woodenSword);
assert.strictEqual(woodenSword!.outcome, 'success');
assert.strictEqual(woodenSword!.emittedSignal, true);
assert.strictEqual(woodenSword!.restorationRequired, false);
assert.strictEqual(woodenSword!.signal?.afterWeight, 18);

const featurelessDiamond = reinforcementBridge.attempts.find(
  (entry) => entry.id === 'featureless-diamond'
);
assert.ok(featurelessDiamond);
assert.strictEqual(featurelessDiamond!.outcome, 'fizzle');
assert.strictEqual(featurelessDiamond!.blockedReason, 'fizzle');
assert.strictEqual(featurelessDiamond!.emittedSignal, false);
assert.strictEqual(featurelessDiamond!.restorationRequired, true);

const fragileLightbulb = reinforcementBridge.attempts.find(
  (entry) => entry.id === 'fragile-lightbulb'
);
assert.ok(fragileLightbulb);
assert.strictEqual(fragileLightbulb!.outcome, 'shatter');
assert.strictEqual(fragileLightbulb!.blockedReason, 'shatter');
assert.strictEqual(fragileLightbulb!.emittedSignal, false);
assert.strictEqual(fragileLightbulb!.restorationRequired, false);

const directSignal = buildTransformationFamilySignalFromReinforcementAttempt({
  id: 'single-success',
  attempt: {
    target: {
      crossings: 3,
      weight: 2,
      capacity: 9,
      invariant: 7,
    },
    analysis: {
      mappedCrossings: 3,
      totalCrossings: 3,
      accuracy: 100,
    },
    energy: 4,
  },
});

assert.deepStrictEqual(directSignal, {
  id: 'single-success',
  beforeCrossings: 3,
  afterCrossings: 3,
  beforeWeight: 2,
  afterWeight: 6,
});

const blockedSignal = buildTransformationFamilySignalFromReinforcementAttempt({
  id: 'single-featureless',
  attempt: {
    target: {
      crossings: 0,
      weight: 5,
      capacity: 9,
      invariant: 8,
    },
    analysis: {
      mappedCrossings: 0,
      totalCrossings: 0,
      accuracy: 100,
    },
    energy: 4,
  },
});

assert.strictEqual(blockedSignal, undefined);

const decompositionBridge = deriveTransformationFamilyFromDecompositionAttempts(
  {
    generatedAt: '2026-04-10T03:00:00.000Z',
    source: 'decomposition-bridge-suite',
    attempts: [
      {
        id: 'strip-barrier',
        object: {
          crossings: 7,
          weight: 10,
          capacity: 12,
        },
        budget: 5,
      },
      {
        id: 'featureless-dust',
        object: {
          crossings: 0,
          weight: 5,
          capacity: 3,
        },
        budget: 4,
      },
      {
        id: 'zero-budget',
        object: {
          crossings: 6,
          weight: 4,
          capacity: 6,
        },
        budget: 0,
      },
    ],
  }
);

assert.strictEqual(decompositionBridge.generatedAt, '2026-04-10T03:00:00.000Z');
assert.strictEqual(decompositionBridge.source, 'decomposition-bridge-suite');
assert.strictEqual(decompositionBridge.aggregate.totalAttempts, 3);
assert.strictEqual(
  decompositionBridge.aggregate.effectiveDecompositionCount,
  1
);
assert.strictEqual(decompositionBridge.aggregate.noOpCount, 2);
assert.strictEqual(decompositionBridge.aggregate.fullyDecomposedCount, 0);
assert.strictEqual(decompositionBridge.aggregate.featurelessBeforeCount, 1);
assert.strictEqual(decompositionBridge.aggregate.featurelessAfterCount, 1);
assert.strictEqual(decompositionBridge.formalization.aggregate.total, 3);
assert.strictEqual(
  decompositionBridge.formalization.aggregate.decompositionCount,
  1
);
assert.strictEqual(
  decompositionBridge.formalization.aggregate.unclassifiedCount,
  2
);

const stripBarrier = decompositionBridge.attempts.find(
  (entry) => entry.id === 'strip-barrier'
);
assert.ok(stripBarrier);
assert.strictEqual(stripBarrier!.effectiveDecomposition, true);
assert.strictEqual(stripBarrier!.fullyDecomposed, false);
assert.strictEqual(stripBarrier!.signal.afterCrossings, 2);
assert.strictEqual(stripBarrier!.signal.afterWeight, 5);

const featurelessDust = decompositionBridge.attempts.find(
  (entry) => entry.id === 'featureless-dust'
);
assert.ok(featurelessDust);
assert.strictEqual(featurelessDust!.featurelessBefore, true);
assert.strictEqual(featurelessDust!.featurelessAfter, true);
assert.strictEqual(featurelessDust!.effectiveDecomposition, false);

const zeroBudget = decompositionBridge.attempts.find(
  (entry) => entry.id === 'zero-budget'
);
assert.ok(zeroBudget);
assert.strictEqual(zeroBudget!.effectiveDecomposition, false);
assert.strictEqual(zeroBudget!.signal.afterCrossings, 6);
assert.strictEqual(zeroBudget!.signal.afterWeight, 4);

const directDecompositionSignal =
  buildTransformationFamilySignalFromDecompositionAttempt({
    id: 'single-decomposition',
    object: {
      crossings: 4,
      weight: 6,
      capacity: 9,
    },
    budget: 3,
  });

assert.deepStrictEqual(directDecompositionSignal, {
  id: 'single-decomposition',
  beforeCrossings: 4,
  afterCrossings: 1,
  beforeWeight: 6,
  afterWeight: 3,
});

console.log('transformation-family-formalization: all tests passed');
